const GLOSSARY_CRISC = [
  { term:"Annualized Loss Expectancy", definition:"The expected monetary loss from a risk over a one-year period, calculated as single loss expectancy multiplied by the annualized rate of occurrence. It supports cost-benefit analysis of controls." },
  { term:"Annualized Loss Expectancy (ALE)", definition:"The expected yearly monetary loss from a risk, calculated as single loss expectancy multiplied by the annualized rate of occurrence. It supports cost-benefit analysis of controls." },
  { term:"Annualized Rate of Occurrence", definition:"The estimated frequency with which a specific risk event is expected to occur within a single year. It is combined with single loss expectancy to derive annualized loss expectancy." },
  { term:"Annualized Rate of Occurrence (ARO)", definition:"The estimated frequency with which a specific risk event is expected to occur in a year. It provides the likelihood input for annualized loss calculations." },
  { term:"Audit Trail", definition:"A chronological record of system activities that provides evidence for reconstructing and examining events — critical for risk management accountability." },
  { term:"Black Swan Event", definition:"A highly improbable, unpredictable event with severe consequences that is rationalized only in hindsight. Its unforeseeable nature challenges conventional risk models and argues for resilience over pure prediction." },
  { term:"Bottom-Up Risk Assessment", definition:"An approach where risks are identified at the process, asset, or system level and aggregated upward. It captures operational detail but requires consolidation to reveal enterprise significance." },
  { term:"Bow-Tie Analysis", definition:"A visual risk technique mapping threats and preventive controls on the left, a central hazardous event, and consequences with mitigating controls on the right. It links causes and outcomes to illustrate barrier effectiveness for a single risk event." },
  { term:"Business Continuity Plan", definition:"A documented set of procedures that enables an organization to continue or resume critical functions during and after a disruption. It is informed by the business impact analysis." },
  { term:"Business Impact Analysis", definition:"A process that identifies critical business functions, the minimum resources required to sustain them, and the impact of their disruption over time." },
  { term:"Business Impact Analysis (BIA)", definition:"A process identifying critical business functions and quantifying the operational and financial effects of their disruption over time. It establishes recovery priorities and objectives that drive continuity planning." },
  { term:"Change Management", definition:"Formal process for controlling modifications to IT systems to prevent unauthorized changes that could introduce new risks." },
  { term:"COBIT", definition:"Control Objectives for Information and Related Technologies — ISACA's governance framework aligning IT processes with business objectives and risk management." },
  { term:"Compensating Control", definition:"An alternative control implemented when a primary or preferred control is not feasible, providing a comparable level of protection. It must satisfy the intent and rigor of the original requirement." },
  { term:"Compliance Risk", definition:"Risk of legal or regulatory sanctions, financial penalties, or reputational damage from failing to comply with applicable laws and regulations." },
  { term:"Concentration Risk (Vendor)", definition:"The risk of over-dependence on a single vendor, platform, or provider such that its failure causes outsized disruption. Diversification or exit strategies mitigate this concentration." },
  { term:"Configuration Management", definition:"The discipline of establishing and maintaining accurate records of system components and their settings throughout their lifecycle. It supports change control, security baselines, and incident diagnosis." },
  { term:"Continuous Control Monitoring (CCM)", definition:"The use of automated tools to test control operation frequently or in real time, rather than periodically. It provides timely assurance and rapid detection of control failures." },
  { term:"Control", definition:"A safeguard or countermeasure used to reduce the likelihood or impact of a risk. Controls can be preventive, detective, or corrective." },
  { term:"Control Deficiency", definition:"A gap or weakness in a control that prevents it from fully achieving its risk reduction objective." },
  { term:"Control Design Effectiveness", definition:"An assessment of whether a control, as designed, is capable of preventing or detecting the risk it addresses. A well-designed control can still fail if not operating effectively." },
  { term:"Control Effectiveness", definition:"The degree to which a control achieves its intended objective of reducing risk likelihood or impact." },
  { term:"Control Framework", definition:"A structured set of controls organized to manage specific risk areas. Examples include COBIT, NIST CSF, ISO 27001 Annex A." },
  { term:"Control Gap", definition:"The difference between the control coverage required to meet a risk objective and the controls actually in place or operating. Identifying gaps drives remediation to bring residual risk within appetite." },
  { term:"Control Operating Effectiveness", definition:"An assessment of whether a control is actually functioning consistently and as intended over a period. Testing operating effectiveness is essential because good design does not guarantee reliable execution." },
  { term:"Control Owner", definition:"The individual accountable for the design, operation, and effectiveness of a specific control. The control owner ensures the control performs as intended and reports on its status." },
  { term:"Control Self-Assessment", definition:"A process in which business and process owners evaluate the adequacy and effectiveness of their own controls. It increases ownership and surfaces control gaps from those closest to the process." },
  { term:"Control Self-Assessment (CSA)", definition:"A process in which process owners assess the design and effectiveness of their own controls, often via workshops or questionnaires. It builds ownership and awareness but requires validation to counter bias." },
  { term:"Control Testing", definition:"The evaluation of whether a control is designed appropriately and operating effectively over a period. Results provide assurance and identify control deficiencies requiring remediation." },
  { term:"Corrective Control", definition:"A control that acts to remediate and restore normal conditions after a risk event has been detected, such as restoring from backup or patching. It limits the duration and impact of incidents." },
  { term:"COSO ERM Framework", definition:"An enterprise risk management framework integrating risk with strategy and performance across five components and twenty principles. It emphasizes governance, culture, and value creation rather than a checklist of controls." },
  { term:"Current Risk", definition:"The actual risk level given controls as they presently operate, which may differ from designed residual risk if controls are partially effective. It reflects the real-time exposure the organization faces today." },
  { term:"Data Classification", definition:"The categorization of data by sensitivity and criticality to determine appropriate handling and protection. It ensures controls are proportionate to the value and risk of the information." },
  { term:"Data Lifecycle Management", definition:"The governance of data from creation and storage through use, sharing, archival, and secure disposal. Managing each stage reduces risks related to privacy, integrity, and retention compliance." },
  { term:"Delphi Technique", definition:"A structured, anonymous, iterative expert-elicitation method used to build consensus on risk estimates or scenarios. Anonymity reduces dominance bias and groupthink while multiple rounds converge opinions." },
  { term:"Detective Control", definition:"A control designed to identify and alert on a risk event, error, or anomaly after it has occurred, such as log monitoring or reconciliations. It enables timely response and correction." },
  { term:"Deterrent Control", definition:"A control that discourages threat actors from attempting an action, such as warning banners or visible surveillance. It reduces likelihood by increasing perceived risk or effort for the attacker." },
  { term:"Directive Control", definition:"A control that guides or mandates desired behavior, such as policies, standards, and procedures. It establishes the expectations that other control types enforce." },
  { term:"Disaster Recovery Plan", definition:"A documented plan focused on restoring IT systems, data, and infrastructure following a disruptive event. It supports the broader business continuity plan by meeting defined RTOs and RPOs." },
  { term:"DREAD Risk Rating", definition:"A threat-scoring model rating Damage, Reproducibility, Exploitability, Affected users, and Discoverability to prioritize vulnerabilities. Though subjective, it provides a repeatable structure for ranking threats." },
  { term:"Emerging Risk", definition:"A newly developing or evolving risk whose impact and likelihood are not yet well understood, often arising from new technology, regulation, or market change. It requires proactive monitoring and scenario analysis." },
  { term:"Encryption", definition:"The transformation of data into an unreadable form using cryptographic keys to protect confidentiality and integrity. It safeguards data at rest and in transit against unauthorized disclosure." },
  { term:"Encryption at Rest", definition:"The protection of stored data by rendering it unreadable without a decryption key. It mitigates the risk of data exposure from theft or unauthorized access to storage media." },
  { term:"Encryption in Transit", definition:"The protection of data as it moves across networks using protocols such as TLS. It mitigates interception and eavesdropping risks between endpoints." },
  { term:"Enterprise Architecture", definition:"A holistic blueprint describing an organization's business processes, information, applications, and technology and how they align with strategy. It helps identify risk, redundancy, and integration gaps." },
  { term:"Enterprise Risk Management", definition:"A structured, enterprise-wide approach to identifying, assessing, responding to, and monitoring risks that could affect the achievement of objectives. It integrates risk considerations into strategy and decision-making." },
  { term:"Event Tree Analysis (ETA)", definition:"A forward, inductive technique that models the range of outcomes following an initiating event based on success or failure of subsequent barriers. It complements fault tree analysis by exploring consequence pathways." },
  { term:"Exception Management", definition:"The formal process of requesting, evaluating, approving, and tracking deviations from established policies, standards, or controls. Approved exceptions are time-bound and require documented risk acceptance." },
  { term:"Exposure", definition:"The condition of being susceptible to loss from a threat exploiting a vulnerability, often quantified as the assets or value at stake. Managing exposure focuses on limiting what can be affected." },
  { term:"Exposure Factor", definition:"The percentage of an asset's value that would be lost if a particular risk event occurred. It is used to calculate single loss expectancy in quantitative analysis." },
  { term:"Exposure Factor (EF)", definition:"The proportion of an asset's value that would be lost if a specific threat event occurred, expressed as a percentage. It is a key input to calculating single loss expectancy." },
  { term:"FAIR (Factor Analysis of Information Risk)", definition:"A quantitative risk model that decomposes risk into loss event frequency and loss magnitude, further broken into factors like threat event frequency, vulnerability, and primary/secondary loss. It enables risk to be expressed in financial (monetary) terms for comparison and prioritization." },
  { term:"Fault Tree Analysis (FTA)", definition:"A top-down, deductive technique using Boolean logic to trace how combinations of lower-level failures lead to a defined undesired top event. It helps identify root causes and quantify failure probabilities of complex systems." },
  { term:"Fourth-Party Risk", definition:"The risk introduced by the subcontractors and suppliers of an organization's direct third parties. It is harder to see and control, requiring visibility into the extended supply chain." },
  { term:"Governance", definition:"The system of rules, practices, and processes by which an organization is directed and controlled, including risk oversight structures." },
  { term:"GRC Platform", definition:"An integrated software system supporting governance, risk, and compliance activities such as risk registers, control libraries, assessments, and reporting. It centralizes data to improve consistency and enterprise-wide visibility." },
  { term:"Heat Map", definition:"A visual matrix that plots risks by likelihood and impact using color coding to convey severity. It helps stakeholders quickly prioritize risks and communicate the risk profile." },
  { term:"Identity and Access Management", definition:"The framework of policies and technologies that ensures the right individuals have appropriate access to resources at the right time. It enforces principles such as least privilege and segregation of duties." },
  { term:"Identity and Access Management (IAM)", definition:"The disciplines and technologies that ensure the right individuals have appropriate access to resources at the right times. It is foundational to enforcing least privilege and accountability." },
  { term:"Impact", definition:"The magnitude of harm or consequence that results if a risk event occurs, measured in financial, operational, reputational, or regulatory terms. Together with likelihood it defines risk severity." },
  { term:"Incident Response", definition:"The organized process for detecting, containing, eradicating, and recovering from security or operational incidents. A defined plan reduces impact and supports lessons learned and reporting." },
  { term:"Inherent Risk", definition:"The risk that exists before any controls are applied. Represents the raw exposure level without mitigation." },
  { term:"ISO 31000", definition:"An international standard providing principles and generic guidelines for enterprise risk management applicable to any organization. It defines a framework and process (establish context, assess, treat, monitor, communicate) but is not certifiable." },
  { term:"ISO/IEC 27005", definition:"The standard providing guidelines for information security risk management, supporting the ISMS requirements of ISO 27001. It details context establishment, risk assessment, treatment, acceptance, and monitoring specific to information security." },
  { term:"IT Risk Management", definition:"The discipline of identifying, assessing, and managing risks arising from the use of information technology in business operations." },
  { term:"Key Control Indicator", definition:"A metric that measures the effectiveness and performance of a specific control over time. KCIs help detect control degradation before it results in a risk event." },
  { term:"Key Control Indicator (KCI)", definition:"A metric measuring whether a control is operating effectively and as designed. Deteriorating KCIs indicate control weakness that may increase residual risk." },
  { term:"Key Performance Indicator", definition:"A metric that measures how effectively an organization or process is achieving its objectives. In risk management, KPIs help evaluate whether controls and activities deliver intended outcomes." },
  { term:"Key Performance Indicator (KPI)", definition:"A metric measuring achievement of objectives or process performance. In risk management KPIs are distinguished from KRIs, which measure exposure rather than outcomes." },
  { term:"Key Risk Indicator", definition:"A forward-looking metric that signals when risk exposure is increasing toward or beyond acceptable thresholds, enabling proactive management." },
  { term:"Key Risk Indicator (KRI)", definition:"A metric that provides an early signal of increasing risk exposure, often forward-looking. Effective KRIs have defined thresholds that trigger escalation or response before risk materializes." },
  { term:"Lagging Indicator", definition:"A metric that measures outcomes after events have occurred, such as incident counts or losses. It confirms performance but offers limited opportunity for prevention." },
  { term:"Leading Indicator", definition:"A predictive metric that signals potential future changes in risk before an event occurs, enabling proactive action. Examples include patch backlog growth or rising failed-login rates." },
  { term:"Least Privilege", definition:"A security principle granting users and processes only the minimum access rights necessary to perform their functions. It limits the potential impact of errors, misuse, and compromised accounts." },
  { term:"Likelihood", definition:"The probability or frequency that a given threat will exploit a vulnerability and result in a risk event. It is combined with impact to determine overall risk level." },
  { term:"Lines of Defense", definition:"A risk governance model: 1st line (operations), 2nd line (risk/compliance functions), 3rd line (internal audit)." },
  { term:"Loss Distribution Approach (LDA)", definition:"An operational risk quantification method that separately models loss frequency and loss severity distributions, then convolves them to estimate aggregate loss. It is commonly used to derive capital requirements at high confidence levels." },
  { term:"Maximum Tolerable Downtime (MTD)", definition:"The longest period a business function can be unavailable before consequences become unacceptable to the organization. It bounds the recovery time objective and shapes continuity strategy." },
  { term:"Monte Carlo Simulation", definition:"A quantitative technique that runs thousands of trials using probability distributions for uncertain variables to produce a distribution of possible outcomes. It supports risk analysis by revealing likelihood ranges rather than single-point estimates." },
  { term:"OCTAVE Allegro", definition:"A streamlined, self-directed information security risk assessment methodology from Carnegie Mellon focused on information assets and their containers. It emphasizes operational risk with a lightweight, workshop-driven approach suitable for organizations without deep risk expertise." },
  { term:"Operational Risk", definition:"Risk of loss from inadequate or failed internal processes, people, systems, or external events — distinct from strategic or financial risk." },
  { term:"PASTA (Process for Attack Simulation and Threat Analysis)", definition:"A seven-stage, risk-centric threat modeling methodology that aligns business objectives with technical attack analysis. It emphasizes attacker simulation and business impact to prioritize mitigations." },
  { term:"Patch Management", definition:"Systematic process for acquiring, testing, and deploying software updates to address vulnerabilities and reduce technical risk." },
  { term:"Preventive Control", definition:"A control designed to stop a risk event or error from occurring in the first place, such as access restrictions or input validation. It reduces the likelihood of undesirable outcomes." },
  { term:"Privileged Access Management (PAM)", definition:"Controls and tools that secure, monitor, and govern elevated administrative accounts. Because privileged accounts pose outsized risk, PAM applies stronger controls such as vaulting, session recording, and just-in-time access." },
  { term:"Qualitative Risk Analysis", definition:"Risk analysis using descriptive categories (high/medium/low) to rank risks when precise numerical data is unavailable." },
  { term:"Quantitative Risk Analysis", definition:"Risk analysis using numerical values and probability estimates to produce monetary risk exposure figures (ALE, SLE)." },
  { term:"Recovery Point Objective", definition:"The maximum acceptable amount of data loss measured in time, defining how far back recovery must reach after a disruption. It determines the required frequency of backups and replication." },
  { term:"Recovery Point Objective (RPO)", definition:"The maximum acceptable amount of data loss measured as the time between the last usable backup and a disruption. It drives the required frequency of data backup or replication." },
  { term:"Recovery Time Objective", definition:"The maximum acceptable length of time a business process or system can be unavailable after a disruption before causing significant harm. It drives recovery strategy and resource decisions." },
  { term:"Recovery Time Objective (RTO)", definition:"The targeted duration within which a process or system must be restored after disruption to avoid unacceptable consequences. It must be shorter than the maximum tolerable downtime." },
  { term:"Reputational Risk", definition:"Risk of damage to an organization's brand, public standing, or stakeholder trust resulting from adverse events or poor decisions." },
  { term:"Residual Risk", definition:"The risk remaining after controls have been applied. Organizations must accept, transfer, or further reduce residual risk." },
  { term:"Residual Risk Acceptance Authority", definition:"The defined level of management empowered to formally accept residual risk based on its magnitude relative to appetite. Escalation thresholds ensure higher risks are accepted by more senior decision-makers." },
  { term:"Return on Security Investment (ROSI)", definition:"A metric comparing the monetary risk reduction from a control against its cost, typically as (ALE reduction minus control cost) divided by control cost. It justifies security spending in financial terms." },
  { term:"Risk", definition:"The probability that a threat will exploit a vulnerability, resulting in harm to an asset. In CRISC, risk is expressed as the combination of likelihood and impact." },
  { term:"Risk Acceptance", definition:"A deliberate decision to accept the consequences of a risk without taking action, when the cost of mitigation exceeds the benefit." },
  { term:"Risk-Adjusted Return on Capital (RAROC)", definition:"A performance metric dividing risk-adjusted return by economic capital allocated for risk. It enables comparison of investments or business lines on a risk-normalized basis." },
  { term:"Risk Aggregation", definition:"The process of combining individual risks to understand the total exposure and potential correlations across the enterprise. It reveals concentrations that may be significant even when individual risks appear minor." },
  { term:"Risk Appetite", definition:"The amount and type of risk an organization is willing to accept in pursuit of its objectives. Defined by the board and senior management." },
  { term:"Risk Assessment", definition:"The overall process of risk identification, analysis, and evaluation. Produces a prioritized list of risks requiring treatment." },
  { term:"Risk Avoidance", definition:"A risk response that eliminates the risk entirely by deciding not to engage in the activity that creates it." },
  { term:"Risk Capacity", definition:"The maximum amount of risk an organization is able to absorb given its financial resources, resilience, and obligations before its viability is threatened. It sets the outer boundary for risk appetite." },
  { term:"Risk Concentration", definition:"An accumulation of exposure to a single counterparty, asset, technology, geography, or vendor that could produce disproportionate loss. Identifying concentrations prevents seemingly small individual risks from combining into a critical one." },
  { term:"Risk Correlation", definition:"The statistical relationship describing how two or more risks move together, positively or negatively. Understanding correlation is essential for accurate aggregation and for avoiding overreliance on diversification." },
  { term:"Risk Culture", definition:"The shared values, beliefs, and behaviors within an organization that shape how risk is identified, discussed, and managed." },
  { term:"Risk Governance", definition:"The framework of policies, structures, roles, and accountabilities through which an organization directs and oversees its risk management activities. It ensures risk decisions align with strategy and stakeholder expectations." },
  { term:"Risk Heat Map", definition:"A graphical matrix plotting risks by likelihood and impact using color gradations to signal severity. It aids prioritization and communication but should be supplemented with quantitative analysis to avoid oversimplification." },
  { term:"Risk Identification", definition:"The process of finding, recognizing, and documenting risks that could affect the achievement of objectives. It produces the inputs used in risk analysis and the risk register." },
  { term:"Risk Interdependency", definition:"The relationship where one risk's occurrence changes the likelihood or impact of another, creating cascading or correlated effects. Recognizing interdependencies is essential to avoid underestimating aggregate exposure." },
  { term:"Risk IT Framework", definition:"An ISACA framework that extends COBIT to IT-related business risk, covering risk governance, evaluation, and response. It bridges enterprise risk management and IT operational risk practices." },
  { term:"Risk Maturity Model", definition:"A framework describing progressive stages of risk management capability, from ad hoc to optimized. It benchmarks current practices and guides improvement of governance, processes, and integration." },
  { term:"Risk Mitigation", definition:"A risk response that reduces the likelihood or impact of a risk through controls, process changes, or other measures." },
  { term:"Risk Monitoring", definition:"The ongoing tracking of risks, controls, and indicators to detect changes in exposure and verify that responses remain effective. It ensures the risk profile stays within appetite over time." },
  { term:"Risk Normalization", definition:"The gradual acceptance of deviant conditions or elevated risk as routine because no adverse event has yet occurred. It erodes vigilance and can precede significant failures, warranting periodic reassessment." },
  { term:"Risk Owner", definition:"The individual or entity accountable for managing a specific risk, ensuring treatment plans are implemented and effective." },
  { term:"Risk Owner Attestation", definition:"A formal confirmation by a risk or control owner that stated risks, controls, and their status are accurate and current. Attestations reinforce accountability and support reliable risk reporting." },
  { term:"Risk Profile", definition:"A consolidated portfolio view of an organization's most significant risks and their aggregate exposure at a point in time. Unlike the detailed register, it communicates overall risk posture to executives and the board." },
  { term:"Risk Ranking", definition:"The process of ordering identified risks by their significance, typically using a combination of likelihood and impact scores. It focuses management attention and resources on the most critical exposures." },
  { term:"Risk Register", definition:"A document recording identified risks, their assessment results, assigned owners, and treatment plans. Central artifact of risk management." },
  { term:"Risk Reporting", definition:"The communication of risk information, including exposures, trends, and control status, to stakeholders and decision-makers. Effective reporting is timely, accurate, and tailored to the audience." },
  { term:"Risk Response Optimization", definition:"The process of selecting the mix of responses that best balances risk reduction against cost, feasibility, and residual exposure. It ensures resources are directed to treatments with the greatest net benefit." },
  { term:"Risk Scenario", definition:"A narrative describing a specific risk event: the threat actor, threat event, vulnerability exploited, and potential business impact." },
  { term:"Risk Scenario Development", definition:"The practice of constructing plausible, concrete descriptions of how a risk could materialize, including actor, threat, event, asset, and consequence. Scenarios make abstract risk tangible and support consistent assessment and response planning." },
  { term:"Risk Sharing", definition:"A response that distributes risk across parties, such as joint ventures, outsourcing, or partnerships. Unlike full transfer, both parties retain a portion of the exposure and responsibility." },
  { term:"Risk Tolerance", definition:"The acceptable deviation from the organization's risk appetite — the operational boundaries within which risk can vary." },
  { term:"Risk Transfer", definition:"A risk response that shifts financial consequences to a third party, typically through insurance or contractual arrangements." },
  { term:"Risk Treatment", definition:"The process of selecting and implementing options to address risk. Options include avoidance, mitigation, transfer, and acceptance." },
  { term:"Risk Treatment Plan", definition:"A documented plan specifying selected risk responses, actions, owners, resources, and timelines for implementation. It operationalizes decisions and enables tracking of remediation to target risk." },
  { term:"Risk Utility Function", definition:"A representation of how an organization or decision-maker values outcomes relative to risk, capturing whether they are risk-averse, neutral, or seeking. It underpins rational decision-making under uncertainty." },
  { term:"Risk Velocity", definition:"The speed with which a risk event, once triggered, produces its impact on the organization. High-velocity risks leave little time to respond, influencing the urgency and design of controls and monitoring." },
  { term:"SDLC Security Gates", definition:"Checkpoints embedded in the software development lifecycle where security requirements, reviews, and testing must be satisfied before progressing. They ensure risk is addressed early rather than after deployment." },
  { term:"Segregation of Duties", definition:"A control that divides critical tasks and privileges among multiple people to prevent any single individual from committing and concealing fraud or error. It is a foundational preventive control." },
  { term:"Segregation of Duties (SoD)", definition:"A control principle dividing critical tasks among multiple individuals so no single person can perpetrate and conceal errors or fraud. It is a core preventive control for reducing insider and process risk." },
  { term:"Semi-Quantitative Analysis", definition:"A hybrid method that assigns numeric scores or ranges to qualitative categories to allow limited calculation and ranking. It offers more rigor than purely qualitative analysis without full quantitative data demands." },
  { term:"Sensitivity Analysis", definition:"A technique that varies one input at a time to determine which variables have the greatest impact on a risk or financial outcome. It helps prioritize which uncertainties warrant the most attention and control." },
  { term:"Single Loss Expectancy", definition:"The monetary loss expected from a single occurrence of a risk event, calculated as asset value multiplied by exposure factor. It is a building block of quantitative risk analysis." },
  { term:"Single Loss Expectancy (SLE)", definition:"The monetary loss expected from a single occurrence of a risk event, calculated as asset value multiplied by exposure factor. It quantifies the impact of one incident." },
  { term:"Software Development Life Cycle", definition:"The structured process for planning, designing, building, testing, deploying, and maintaining software. Embedding controls and security throughout the SDLC reduces the risk of vulnerabilities and defects." },
  { term:"STRIDE Threat Model", definition:"A Microsoft threat-modeling taxonomy categorizing threats as Spoofing, Tampering, Repudiation, Information disclosure, Denial of service, and Elevation of privilege. It helps systematically identify security risks during system design." },
  { term:"Systemic Risk", definition:"The risk that failure of one entity or component triggers cascading failures across an interconnected system or market. It cannot be fully diversified away and often requires collective or regulatory response." },
  { term:"Tail Risk", definition:"The risk of rare, extreme events located in the far ends of a probability distribution, beyond typical expectations. Such low-frequency, high-impact events are often underestimated by standard measures like VaR." },
  { term:"Target Risk", definition:"The desired level of risk the organization aims to achieve after planned treatment, consistent with its risk appetite. It sets the goal against which remediation progress is measured." },
  { term:"Third-Party Risk", definition:"Risk arising from reliance on external vendors, suppliers, or service providers who have access to or process organizational data." },
  { term:"Threat", definition:"Any potential event or action that could cause harm to an organization's assets. Threats can be natural, accidental, or deliberate in origin." },
  { term:"Three Lines Model", definition:"An IIA governance model where the first line owns and manages risk, the second line provides oversight and expertise (risk/compliance functions), and the third line (internal audit) provides independent assurance. It clarifies accountability for risk and control." },
  { term:"Three Lines of Defense", definition:"A governance model separating risk ownership (first line, operational management), risk oversight (second line, risk and compliance functions), and independent assurance (third line, internal audit). It clarifies accountability for managing risk." },
  { term:"Tone at the Top", definition:"The ethical climate and commitment to risk management demonstrated by senior leadership and the board. It signals expected behavior throughout the organization and strongly influences risk culture." },
  { term:"Top-Down Risk Assessment", definition:"An approach where senior leadership identifies strategic risks to major objectives, then cascades analysis downward. It ensures alignment with enterprise goals but may miss granular operational risks." },
  { term:"Total Cost of Ownership (TCO)", definition:"The full lifecycle cost of an asset or control including acquisition, implementation, operation, maintenance, and retirement. Considering TCO prevents underestimating the true cost of risk responses." },
  { term:"Value at Risk (VaR)", definition:"A statistical measure estimating the maximum expected loss over a defined period at a given confidence level (e.g., 95%). In risk management it quantifies potential downside but ignores losses beyond the threshold." },
  { term:"Vulnerability", definition:"A weakness in a system, process, or control that could be exploited by a threat to cause harm." },
  { term:"Zero Trust", definition:"A security model that assumes no implicit trust based on network location and continuously verifies every access request. It reduces risk by enforcing identity, device posture, and least-privilege checks for each transaction." },
  { term:"Inherent vs Residual Risk", definition:"Inherent risk is the exposure that exists before any controls are applied, while residual risk is the exposure that remains after controls operate. CRISC practitioners assess both to judge whether residual risk falls within the enterprise's risk appetite." },
  { term:"Risk Appetite vs Tolerance vs Capacity", definition:"Risk appetite is the broad amount of risk an enterprise is willing to accept in pursuit of value, tolerance is the acceptable variation around specific objectives, and capacity is the maximum risk the enterprise can absorb before threatening viability. Appetite must always stay within capacity." },
  { term:"Loss Event Frequency", definition:"In FAIR, loss event frequency is the probable number of times a loss will occur in a given period, derived from threat event frequency and vulnerability. It combines with loss magnitude to estimate overall risk." },
  { term:"Threat Event Frequency", definition:"In FAIR, threat event frequency is the probable number of times a threat agent will act against an asset within a timeframe. It reflects contact frequency and probability of action independent of control strength." },
  { term:"Vulnerability (FAIR)", definition:"In FAIR, vulnerability is the probability that a threat event becomes a loss event, expressed as the relationship between threat capability and control strength. Higher control strength lowers this probability." },
  { term:"Primary vs Secondary Loss", definition:"Primary loss is the direct cost borne by the organization from a risk event, such as response and replacement, while secondary loss arises from reactions of external stakeholders like fines, lawsuits, and reputation damage. FAIR models both to estimate total loss magnitude." },
  { term:"COSO ERM", definition:"COSO Enterprise Risk Management is a framework integrating risk with strategy and performance across five components and twenty principles. It emphasizes governance, culture, and value creation rather than treating risk as isolated events." },
  { term:"COBIT 2019", definition:"COBIT 2019 is ISACA's framework for the governance and management of enterprise IT, organized around governance and management objectives. It links IT-related risk to enterprise goals through design factors and performance management." },
  { term:"ISO 27005", definition:"ISO 27005 provides guidelines for information security risk management supporting the ISO 27001 ISMS. It details the process of risk identification, analysis, evaluation, and treatment for information security." },
  { term:"NIST RMF", definition:"The NIST Risk Management Framework is a seven-step process (Prepare, Categorize, Select, Implement, Assess, Authorize, Monitor) for managing security and privacy risk in systems. It integrates security into the system development lifecycle." },
  { term:"NIST SP 800-30", definition:"NIST SP 800-30 is the Guide for Conducting Risk Assessments, defining a process to identify threats, vulnerabilities, likelihood, and impact. It supports the assessment steps within the broader NIST RMF." },
  { term:"NIST SP 800-37", definition:"NIST SP 800-37 defines the Risk Management Framework for information systems and organizations, detailing the authorization process. It emphasizes continuous monitoring and organization-wide risk management." },
  { term:"RACI Chart", definition:"A RACI chart maps activities to roles as Responsible, Accountable, Consulted, and Informed. In risk management it clarifies who owns, executes, and is informed about risk and control tasks." },
  { term:"Preventive/Detective/Corrective Control", definition:"Preventive controls stop an event before it occurs, detective controls identify events that have occurred, and corrective controls restore systems after an event. A balanced control environment uses all three types." },
  { term:"Control Maturity Model", definition:"A control maturity model rates the sophistication and consistency of controls along defined levels from ad hoc to optimized. It helps target improvements and benchmark control capability over time." },
  { term:"Capability Maturity Model Integration (CMMI)", definition:"CMMI is a process improvement model with five maturity levels from Initial to Optimizing. Risk practitioners use its scale to assess and communicate the maturity of processes and controls." },
  { term:"Gap Analysis", definition:"Gap analysis compares the current state of controls or capabilities against a desired target or standard to identify deficiencies. It drives remediation planning and prioritization of risk treatment." },
  { term:"Concentration Risk", definition:"Concentration risk arises when exposure is heavily dependent on a single vendor, asset, customer, or geography. Diversification and limits are common treatments to reduce this exposure." },
  { term:"Third-Party/Supply Chain Risk", definition:"Third-party and supply chain risk is the exposure introduced by vendors, partners, and their downstream suppliers. It is managed through due diligence, contractual controls, and ongoing monitoring across the relationship lifecycle." },
  { term:"Risk Ownership", definition:"Risk ownership assigns accountability for managing a specific risk to an individual with authority and resources to act. Clear ownership ensures risks are treated and monitored rather than left unaddressed." },
  { term:"Risk Treatment (Accept/Mitigate/Transfer/Avoid)", definition:"Risk treatment selects a response strategy: accept the risk, mitigate it with controls, transfer it through insurance or contracts, or avoid it by eliminating the activity. The choice balances cost against residual risk within appetite." },
  { term:"Risk Response Plan", definition:"A risk response plan documents the selected treatment, required actions, owners, resources, and timelines for a given risk. It translates a treatment decision into executable and trackable steps." },
  { term:"Residual Risk Acceptance", definition:"Residual risk acceptance is the formal, documented decision by an accountable owner to tolerate remaining risk after treatment. It should be approved at an authority level commensurate with the risk's severity." },
  { term:"Data Analytics in Risk", definition:"Data analytics in risk applies statistical and computational techniques to large datasets to detect patterns, anomalies, and emerging exposures. It enables more predictive and evidence-based risk decisions." },
  { term:"Continuous Auditing/Monitoring", definition:"Continuous auditing and monitoring use automated, ongoing testing of controls and transactions rather than periodic sampling. They provide timely assurance and early detection of control failures." },
  { term:"Line of Business Risk", definition:"Line of business risk is the exposure specific to a particular operating unit's products, processes, and markets. Aggregating it enterprise-wide supports comparable prioritization across units." },
  { term:"Strategic Risk", definition:"Strategic risk is the exposure arising from adverse business decisions, poor execution, or failure to adapt to change. It threatens the achievement of long-term objectives and enterprise value." },
  { term:"IT Risk vs Business Risk", definition:"IT risk is the subset of business risk associated with the use, ownership, and operation of information technology. Framing IT risk in business terms ensures it is prioritized against enterprise objectives." },
  { term:"Risk Maturity", definition:"Risk maturity describes how developed, consistent, and embedded an organization's risk management practices are. Higher maturity correlates with proactive, integrated, and value-adding risk management." },
  { term:"Loss Distribution Approach", definition:"The loss distribution approach models operational risk by combining separate frequency and severity distributions into an aggregate loss distribution. It is used to estimate capital requirements and expected losses." },
  { term:"Qualitative vs Quantitative Risk Analysis", definition:"Qualitative analysis rates risk using descriptive scales like high, medium, and low, while quantitative analysis assigns numeric probability and monetary impact. Many programs combine both, using qualitative screening before quantitative deep dives." },
  { term:"Scenario Analysis", definition:"Scenario analysis examines the outcomes of plausible hypothetical situations to understand potential impacts and control adequacy. It is especially useful for low-frequency, high-impact risks lacking historical data." },
  { term:"Stress Testing", definition:"Stress testing evaluates how systems, portfolios, or controls perform under severe but plausible adverse conditions. It reveals vulnerabilities and capacity limits that normal-condition assessments miss." },
  { term:"Risk-Based Auditing", definition:"Risk-based auditing directs audit effort toward the areas of highest risk to the organization's objectives. It improves assurance efficiency by aligning scope with the risk profile." },
  { term:"Materiality", definition:"Materiality is the threshold at which an error, loss, or risk becomes significant enough to influence stakeholder decisions. It guides where risk and control effort should be concentrated." },
  { term:"Risk Factor", definition:"A risk factor is any condition, event, or characteristic that increases the likelihood or impact of a risk. Identifying risk factors supports the construction of meaningful risk scenarios and KRIs." },
  { term:"Risk Tolerance Threshold", definition:"A risk tolerance threshold is the specific quantitative or qualitative boundary that triggers escalation or action when crossed. Thresholds operationalize appetite and tolerance into measurable trip points for KRIs." },
  { term:"Control Objective", definition:"A control objective is the intended purpose or result that a control is designed to achieve, such as ensuring transaction accuracy. Controls are evaluated by how well they satisfy their stated objectives." },
  { term:"Control Design vs Operating Effectiveness", definition:"Design effectiveness asks whether a control, if operating as intended, would mitigate the risk, while operating effectiveness asks whether it actually functions consistently over time. Both must be tested to conclude a control is effective." },
  { term:"Risk Assessment vs Risk Analysis", definition:"Risk analysis estimates likelihood and impact of individual risks, while risk assessment is the broader process that also evaluates and prioritizes those risks against criteria. Assessment includes analysis plus evaluation for decision-making." },
  { term:"Risk Evaluation", definition:"Risk evaluation compares analyzed risk levels against established criteria and appetite to decide which risks require treatment and in what order. It is the decision-making bridge between analysis and treatment." },
  { term:"Risk Prioritization", definition:"Risk prioritization ranks risks so that limited resources address the most significant exposures first. It typically weighs likelihood, impact, velocity, and alignment with objectives." },
  { term:"Cost-Benefit Analysis of Controls", definition:"Cost-benefit analysis compares the expected reduction in loss from a control against its implementation and operating cost. A control is generally justified only when its benefit exceeds its cost relative to residual risk." },
  { term:"Risk Owner vs Control Owner", definition:"The risk owner is accountable for the overall management of a risk, while the control owner is responsible for operating a specific control mitigating that risk. Separating these roles clarifies accountability across the treatment chain." },
  { term:"Risk Indicator Threshold Calibration", definition:"Threshold calibration sets and tunes the trigger levels of KRIs so alerts are neither too frequent nor too rare. Proper calibration balances early warning against alert fatigue." },
  { term:"Total Cost of Risk", definition:"Total cost of risk aggregates the costs of retained losses, risk transfer, control implementation, and administration. It provides a comprehensive economic view for optimizing risk management spending." },
  { term:"Quantitative Likelihood vs Impact", definition:"Quantitative likelihood expresses probability numerically, such as a frequency or percentage, while quantitative impact expresses consequence in monetary or measurable units. Combining them yields expected loss estimates like ALE." },
  { term:"Risk Transfer via Insurance", definition:"Risk transfer via insurance shifts the financial consequence of a risk to a third party in exchange for premiums. It reduces impact but does not eliminate the underlying risk or accountability." },
  { term:"Risk Retention", definition:"Risk retention is the deliberate decision to bear a risk internally rather than treat or transfer it. It is appropriate when the cost of treatment exceeds the expected loss and residual risk is within appetite." },
  { term:"Root Cause Analysis", definition:"Root cause analysis investigates an incident or control failure to identify the underlying cause rather than symptoms. Addressing root causes prevents recurrence and strengthens the control environment." },
  { term:"Risk Trigger", definition:"A risk trigger is an event or condition that signals a risk is about to materialize or has begun. Defining triggers enables timely activation of response plans and contingency measures." },
  { term:"Contingency Plan", definition:"A contingency plan defines predetermined actions to take if a specific risk materializes despite preventive controls. It reduces impact by ensuring a prepared, rapid response." },
  { term:"Risk Escalation", definition:"Risk escalation is the process of routing risks that exceed defined thresholds to higher authority for decision or action. Clear escalation paths ensure significant risks receive appropriate attention." },
  { term:"Assurance Mapping", definition:"Assurance mapping documents the sources of assurance across the three lines to identify overlaps and gaps in coverage of key risks. It optimizes assurance effort and confirms critical risks are adequately covered." },
  { term:"Risk Treatment Cost-Effectiveness", definition:"Treatment cost-effectiveness evaluates whether a chosen response achieves the required risk reduction at the lowest reasonable cost. It prevents over-controlling low-impact risks and under-controlling significant ones." },
  { term:"Enterprise Risk Appetite Statement", definition:"An enterprise risk appetite statement is a board-approved articulation of the types and amounts of risk the organization will pursue or accept. It anchors risk decisions and cascades into tolerances and thresholds." },
  { term:"Loss Magnitude", definition:"In FAIR, loss magnitude is the probable size of loss from an event, combining primary and secondary losses across cost forms. It pairs with loss event frequency to derive overall risk in financial terms." },
  { term:"Threat Capability", definition:"Threat capability is the skill and resources a threat agent can bring to bear against a control. In FAIR it is compared against control strength to derive vulnerability." },
  { term:"Control Strength", definition:"Control strength, or resistance strength, is the ability of a control to withstand the force of a threat agent. Higher control strength lowers the probability that a threat event becomes a loss event." },
  { term:"Risk Quantification Uncertainty", definition:"Quantification uncertainty acknowledges that risk estimates rely on imperfect data and assumptions, so results are expressed as ranges or distributions. Communicating uncertainty prevents overconfidence in single-point risk figures." },
  { term:"Risk Treatment Prioritization Matrix", definition:"A treatment prioritization matrix ranks proposed responses by risk reduction against cost or effort to sequence remediation. It ensures scarce resources deliver the greatest reduction in exposure first." },
  { term:"Emerging Technology Risk", definition:"Emerging technology risk is the uncertain exposure introduced by adopting new technologies such as AI, cloud, or IoT before their risks are fully understood. It requires adaptive assessment and monitoring as understanding matures." },
  { term:"Risk-Aware Decision Making", definition:"Risk-aware decision making integrates explicit consideration of risk and appetite into business choices at all levels. It embeds risk management into strategy and operations rather than treating it as a separate activity." },
  { term:"Control Rationalization", definition:"Control rationalization streamlines and consolidates overlapping or redundant controls to reduce cost while maintaining coverage. It improves efficiency without increasing residual risk beyond appetite." }
];
GLOSSARY_CRISC.sort((a, b) => a.term.localeCompare(b.term, undefined, { sensitivity: 'base' }));
